// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
// Structure to represent an edge
typedef struct Edge {
    int u, v, capacity, flow;
} Edge;
// Structure to represent a graph
typedef struct Graph {
    int V, E;
    Edge* edges;
} Graph;
// Function to create a graph
Graph* createGraph(int V, int E) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->V = V;
    graph->E = E;
    graph->edges = (Edge*)malloc(E * sizeof(Edge));
    return graph;
}
// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v, int capacity) {
    graph->edges[graph->E].u = u;
    graph->edges[graph->E].v = v;
    graph->edges[graph->E].capacity = capacity;
    graph->edges[graph->E].flow = 0;
    graph->E++;
}
// Function to find the maximum flow using Ford-Fulkerson algorithm
int fordFulkerson(Graph* graph, int source, int sink) {
    int* parent = (int*)malloc(graph->V * sizeof(int));
    int max_flow = 0;
    while (bfs(graph, source, sink, parent)) {
        int path_flow = INF;
        int s = sink;
        while (s != source) {
            int u = parent[s];
            int v = s;
            for (int i = 0; i < graph->E; i++) {
                if (graph->edges[i].u == u && graph->edges[i].v == v) {
                    path_flow = MIN(path_flow, graph->edges[i].capacity - graph->edges[i].flow);
                    break;
                }
            }
            s = parent[s];
        }
        max_flow += path_flow;
        int v = sink;
        while (v != source) {
            int u = parent[v];
            for (int i = 0; i < graph->E; i++) {
                if (graph->edges[i].u == u && graph->edges[i].v == v) {
                    graph->edges[i].flow += path_flow;
                    break;
                }
            }
            v = parent[v];
        }
    }
    free(parent);
    return max_flow;
}
// Function to perform BFS to find an augmenting path
int bfs(Graph* graph, int source, int sink, int* parent) {
    int* visited = (int*)malloc(graph->V * sizeof(int));
    for (int i = 0; i < graph->V; i++) {
        visited[i] = 0;
    }
    queue<int> q;
    q.push(source);
    visited[source] = 1;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int i = 0; i < graph->E; i++) {
            int v = graph->edges[i].v;
            if (!visited[v] && graph->edges[i].capacity - graph->edges[i].flow > 0) {
                q.push(v);
                visited[v] = 1;
                parent[v] = u;
                if (v == sink) {
                    free(visited);
                    return 1;
                }
            }
        }
    }
    free(visited);
    return 0;
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Graph* graph = createGraph(N, M);
    for (int i = 0; i < M; i++) {
        int u, v, capacity;
        scanf("%d %d %d", &u, &v, &capacity);
        addEdge(graph, u - 1, v - 1, capacity);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 0) {
            int source, sink;
            scanf("%d %d", &source, &sink);
            printf("%d\n", fordFulkerson(graph, source - 1, sink - 1));
        } else {
            int x, new_capacity;
            scanf("%d %d", &x, &new_capacity);
            graph->edges[x - 1].capacity = new_capacity;
        }
    }
    free(graph->edges);
    free(graph);
    return 0;
}

