};
// Function to create a graph
Graph* createGraph(int V, int E) {
    Graph* graph = new Graph;
    graph->V = V;
    graph->E = E;
    graph->edges = new Edge[E];
    return graph;
}
// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v, int capacity) {
    graph->edges[graph->E].u = u;
    graph->edges[graph->E].v = v;
    graph->edges[graph->E].capacity = capacity;
    graph->edges[graph->E].flow = 0;
    graph->E++;
}
// Function to find the maximum flow using Ford-Fulkerson algorithm
int fordFulkerson(Graph* graph, int source, int sink) {
    int* parent = new int[graph->V];
    int max_flow = 0;
    while (bfs(graph, source, sink, parent)) {
        int path_flow = INF;
        int s = sink;
        while (s != source) {
            int u = parent[s];
            int v = s;
            for (int i = 0; i < graph->E; i++) {
                if (graph->edges[i].u == u && graph->edges[i].v == v) {
                    path_flow = min(path_flow, graph->edges[i].capacity - graph->edges[i].flow);
                    break;
                }
            }
            s = parent[s];
        }
        max_flow += path_flow;
        int v = sink;
        while (v != source) {
            int u = parent[v];
            for (int i = 0; i < graph->E; i++) {
                if (graph->edges[i].u == u && graph->edges[i].v == v) {
                    graph->edges[i].flow += path_flow;
                    break;
                }
            }
            v = parent[v];
        }
    }
    delete[] parent;
    return max_flow;
}
// Function to perform BFS to find an augmenting path
bool bfs(Graph* graph, int source, int sink, int* parent) {
    bool* visited = new bool[graph->V];
    for (int i = 0; i < graph->V; i++) {
        visited[i] = false;
    }
    queue<int> q;
    q.push(source);
    visited[source] = true;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int i = 0; i < graph->E; i++) {
            int v = graph->edges[i].v;
            if (!visited[v] && graph->edges[i].capacity - graph->edges[i].flow > 0) {
                q.push(v);
                visited[v] = true;
                parent[v] = u;
                if (v == sink) {
                    delete[] visited;
                    return true;
                }
            }
        }
    }
    delete[] visited;
    return false;
}
int main() {
    int N, M;
    cin >> N >> M;
    Graph* graph = createGraph(N, M);
    for (int i = 0; i < M; i++) {
        int u, v, capacity;
        cin >> u >> v >> capacity;
        addEdge(graph, u - 1, v - 1, capacity);
    }
    int Q;
    cin >> Q;
    for (int i = 0; i < Q; i++) {
        int type;
        cin >> type;
        if (type == 0) {
            int source, sink;
            cin >> source >> sink;
            cout << fordFulkerson(graph, source - 1, sink - 1) << endl;
        } else {
            int x, new_capacity;
            cin >> x >> new_capacity;
            graph->edges[x - 1].capacity = new_capacity;
        }
    }
    delete[] graph->edges;
    delete graph;
    return 0;
}
